55	function buildMerchGroupMap(merchGroupData) {
56	  const map = new Map();
57	  if (!merchGroupData) {
58	    return map;
59	  }
60	  for (const row of merchGroupData) {
61	    const values = row.dataValues || row;
62	    const mgId = values.mg_id;
63	    if (mgId != null && mgId !== '') {
64	      map.set(String(mgId), values);
65	    }
66	  }
67	  return map;
68	}
