347	Customer.getAll = async (req, result) => {
348	  let token = req.headers.authorization;
349	  let user = await getUserInfo(token)
350	  let status;
351	  let condition;
352	  let order;
353	  let divisionCodeArray = ['Lic,Gen', 'Gen,Lic'];
