360	  }
361	  for (var i = 0; req.body.divisionCode.length > i; i++) {
362	    divisionCodeArray.push(req.body.divisionCode[i].divCode_code)
363	  }
364	  for (var i = 0; req.body.divisionStatus.length > i; i++) {
365	    divisionStatusArray.push(req.body.divisionStatus[i].RFQItemStatus_id)
366	  }
367	  if (user.role == 'vendor') {
368	    if ((!user.factory_id || !user.vendor_id) && user.email) {
369	      const data = await sql.vendor.findOne({
370	        where: {
371	          vendor_email: user.email
372	        }
373	      });
374	      if (data) {
375	        user.factory_id = data.factory_id_fk;
376	        user.vendor_id = data.vendor_id;
377	      }
378	    }
379	
380	    const vendorFilterIds = [...new Set([user.vendor_id, user.factory_id].filter(id => id != null && id !== ''))];
381	    if (vendorFilterIds.length === 0) {
382	      result(null, []);
383	      return;
384	    }
385	    const vendorFilter = vendorFilterIds.length === 1 ? vendorFilterIds[0] : { [Op.or]: vendorFilterIds };
386	
387	    if (user.factory_id) {
388	      // Lazy per-vendor sweep: archive this factory's own quote rows that were priced
389	      // and quoted >3 months ago. Per-vendor (RFQVendor_archived), so it never affects
390	      // Sourcing or other factories. Failure here must not break the listing.
391	      try {
392	        await archiveStaleVendorQuotes(sql, user.factory_id);
393	      } catch (e) {
394	        console.warn('archiveStaleVendorQuotes skipped:', e.message);
395	      }
396	    }
397	
398	    // For vendors the archive/active split is driven by THEIR own quote row, not the
399	    // global RFQItem.rfqItem_archive flag. Archive tab → archived rows; active → the rest.
400	    const vendorArchived = req.body.status == 'archive'
401	      ? true
402	      : { [Op.or]: [false, null] };
403	
404	    if (req.body.filterd_rfq == 'true') {
405	      // Allow showing the highlighted item OR any item assigned to this vendor/factory.
406	      condition = {
407	        '$RFQVendors.RFQVendor_archived$': vendorArchived,
408	        '$RFQItem.rfqItem_divCode_id_fk$': { [Op.or]: divisionCodeArray },
409	        '$RFQItem.rfqItem_active$': { [Op.or]: divisionStatusArray },
410	        [Op.or]: [
411	          { '$RFQVendors.vendor_id_fk$': vendorFilter },
412	          { 'rfqItem_style_number': req.body.highlightedItem }
413	        ]
414	      }
415	      order = [Sequelize.literal('"RFQVendor_id" DESC')]
416	    } else {
417	      condition = {
418	        '$RFQVendors.RFQVendor_archived$': vendorArchived,
419	        '$RFQItem.rfqItem_divCode_id_fk$': {
420	          [Op.or]: divisionCodeArray
421	        },
422	        '$RFQItem.rfqItem_active$': {
423	          [Op.or]: divisionStatusArray
424	        },
425	        '$RFQVendors.vendor_id_fk$': vendorFilter
426	      }
427	      order = [Sequelize.literal('"RFQVendor_id" DESC')]
428	    }
429	
430	
431	
432	  } else {
433	
434	    condition = {
435	      '$RFQItem.rfqItem_archive$': status,
436	      '$RFQItem.rfqItem_divCode_id_fk$': {
437	        [Op.or]: divisionCodeArray
438	      },
439	      '$RFQItem.rfqItem_active$': {
440	        [Op.or]: divisionStatusArray
441	      },
442	    }
443	    //order = [Sequelize.literal('"RFQGroup_name"'), Sequelize.literal('"rfqItem_id" DESC')]
444	    order = [Sequelize.literal('"rfqItem_id" DESC')]
445	    subQuery = true
446	  }
447	
448	  const rfqVendorsInclude = buildRfqVendorsInclude(sql, user);
449	
450	  try {
451	    const [data, merchGroupData, whsecost] = await Promise.all([
452	      sql.RFQItem.findAll({
453	        order: order,
454	        subQuery: subQuery,
455	        attributes: { exclude: RFQ_LIST_ITEM_EXCLUDE_ATTRIBUTES },
456	        as: 'RFQItem',
457	        where: condition,
458	        include: buildRfqListLookupIncludes(sql, rfqVendorsInclude),
459	      }),
460	      getCachedMerchGroup(sql),
461	      getCachedWhsePrice(sql),
462	    ]);
463	
464	    if (!data) {
465	      result(null, null);
466	      return;
467	    }
468	
469	    const merchGroupMap = buildMerchGroupMap(merchGroupData);
470	    let items = await utility.remapRFQItem(data, merchGroupData, {
471	      merchGroupMap,
472	      whsecost,
473	    });
474	    items = items.sort(function (a, b) {
475	      return (a['Price Code'] == req.body.highlightedItem) ? -1 : 1;
476	    });
477	
478	    result(null, items);
479	  } catch (err) {
480	    result(err, null);
481	  }
482	};
