484	function array_move(arr, old_index, new_index) {
485	  if (new_index >= arr.length) {
486	    var k = new_index - arr.length + 1;
487	    while (k--) {
488	      arr.push(undefined);
489	    }
490	  }
491	  arr.splice(new_index, 0, arr.splice(old_index, 1)[0]);
492	  return arr; // for testing
493	};
